import requests

# Примерен код за използване на OpenWeatherMap API
def get_weather_data(city):
    api_key = 'YOUR_API_KEY'
    url = f'https://api.openweathermap.org/data/2.5/forecast?q={city}&appid={api_key}'
    response = requests.get(url)
    return response.json()

# Примерен код за използване на NOAA API
def get_energy_data(city):
    url = f'https://api.noaa.gov/forecast?city={city}&format=json'
    response = requests.get(url)
    return response.json()

if __name__ == '__main__':
    print('Patch applied')

